import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Home, Upload, PlaySquare, HelpCircle } from 'lucide-react';

export default function FloatingDock() {
    const navigate = useNavigate();
    const location = useLocation();
    const [scrolled, setScrolled] = useState(false);

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 20);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const navItems = [
        { path: '/', icon: Home, label: 'Home' },
        { path: '/upload', icon: Upload, label: 'Upload' },
        { path: '/dashboard', icon: PlaySquare, label: 'Dashboard' },
        { path: '/quiz', icon: HelpCircle, label: 'Quiz' },
    ];

    return (
        <div style={{
            position: 'fixed',
            bottom: '2rem',
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 1000,
            transition: 'all 0.3s ease',
            opacity: scrolled ? 0.9 : 1
        }}>
            <nav className="flex items-center gap-2 p-3 bg-white/80 dark:bg-slate-900/65 backdrop-blur-md rounded-full border border-gray-200 dark:border-white/10 shadow-[0_4px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_20px_40px_rgba(0,0,0,0.4),inset_0_1px_0_rgba(255,255,255,0.1)] transition-colors duration-500">
                {navItems.map(({ path, icon: Icon, label }) => {
                    const isActive = location.pathname === path || (path !== '/' && location.pathname.startsWith(path));
                    return (
                        <div key={path} className="dock-item-container" style={{ position: 'relative' }}>
                            <button
                                onClick={() => navigate(path)}
                                title={label}
                                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 ${isActive ? 'bg-cyan-400/15 text-cyan-400 scale-110' : 'bg-transparent text-slate-500 hover:text-slate-800 hover:bg-slate-100 hover:-translate-y-1 dark:text-white/60 dark:hover:text-white dark:hover:bg-white/10'}`}
                            >
                                <Icon size={24} />
                            </button>
                            {/* Stylish Tooltip */}
                            <span className="dock-tooltip">
                                {label}
                            </span>
                        </div>
                    );
                })}
            </nav>

            <style>{`
                .dock-item-container:hover .dock-tooltip {
                    opacity: 1;
                    visibility: visible;
                    transform: translateX(-50%) translateY(-10px);
                }
                .dock-tooltip {
                    position: absolute;
                    bottom: 100%;
                    left: 50%;
                    transform: translateX(-50%) translateY(0px);
                    background: rgba(255, 255, 255, 0.9);
                    color: #0f172a;
                    padding: 0.35rem 0.75rem;
                    border-radius: 0.5rem;
                    font-size: 0.75rem;
                    font-weight: 600;
                    letter-spacing: 0.05em;
                    white-space: nowrap;
                    border: 1px solid rgba(0, 0, 0, 0.1);
                    opacity: 0;
                    visibility: hidden;
                    transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
                    pointer-events: none;
                    margin-bottom: 0.5rem;
                    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.5);
                }
                .dock-tooltip::after {
                    content: '';
                    position: absolute;
                    top: 100%;
                    left: 50%;
                    transform: translateX(-50%);
                    border-width: 5px;
                    border-style: solid;
                    border-color: rgba(255, 255, 255, 0.9) transparent transparent transparent;
                }
                .dark .dock-tooltip {
                    background: rgba(15, 23, 42, 0.9);
                    color: white;
                    border-color: rgba(255, 255, 255, 0.1);
                    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.5);
                }
                .dark .dock-tooltip::after {
                    border-color: rgba(15, 23, 42, 0.9) transparent transparent transparent;
                }
            `}</style>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Play, Pause, Volume2, Maximize, BrainCircuit, Download, Share2, CheckCircle2, ChevronRight, Zap, Send, Sparkles } from 'lucide-react';
import { mockChapters, mockTakeaways } from '../../lib/mockData';

export default function DashboardView() {
    const navigate = useNavigate();
    const location = useLocation();

    // Fallback UI data
    const videoData = location.state || {
        title: mockChapters[0].title,
        duration: mockChapters[0].duration,
        chapter: 'Chapter 1',
        id: mockChapters[0].id
    };
    const [isPlaying, setIsPlaying] = useState(false);
    // Use title to match since mock data IDs vary between Curriculum and Dashboard views
    const [activeVideoId, setActiveVideoId] = useState(videoData.activeVideoId || mockChapters[0].id);

    // We also need an ID for mockTakeaways lookup fallback // Fallback logic is largely moot with dynamic data but we'll try to find it
    const [activeChapterId, setActiveChapterId] = useState(activeVideoId);

    const [activeLanguage, setActiveLanguage] = useState('EN');
    const [activeTab, setActiveTab] = useState('curriculum'); // 'curriculum' or 'ask_ai'
    const [chatInput, setChatInput] = useState('');
    const [chatMessages, setChatMessages] = useState([
        { role: 'ai', content: `Hi! I am your AI companion for this course. Do you have any questions about "${videoData.title}"?` }
    ]);

    // Removed hardcoded useEffect sync

    const togglePlay = () => setIsPlaying(!isPlaying);

    const handleSendMessage = (e) => {
        e.preventDefault();
        if (!chatInput.trim()) return;

        const newMessages = [...chatMessages, { role: 'user', content: chatInput }];
        setChatMessages(newMessages);
        setChatInput('');

        // Mock AI response
        setTimeout(() => {
            setChatMessages(prev => [...prev, { role: 'ai', content: 'That is a great question! Based on this lecture, the key factor energy transfer is...' }]);
        }, 1000);
    };

    // Determine active video details from state or fallback
    const currentVideo = videoData.playlist ? videoData.playlist.find(v => v.id === activeVideoId) : mockChapters.find(c => c.id === activeVideoId);
    const displayTitle = currentVideo?.title || videoData.title;
    const displayDuration = currentVideo?.duration || videoData.duration;
    const displayChapterTitle = videoData.chapterTitle || videoData.chapter;

    // Prepare curriculum list 
    let displayChapters = videoData.playlist || mockChapters;

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-[#0a0f1c] transition-colors duration-500 font-sans pb-32 text-slate-900 dark:text-white overflow-hidden relative" style={{ fontFamily: "'Inter', system-ui, sans-serif" }}>

            {/* Background Spotlights & Noise - Dynamic */}
            <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden mix-blend-multiply dark:mix-blend-normal">
                <div className="absolute inset-0" style={{ background: 'radial-gradient(ellipse 800px 500px at 20% 30%, rgba(34,211,238,0.05), transparent)' }}></div>
                <div className="absolute inset-0" style={{ background: 'radial-gradient(ellipse 800px 500px at 80% 70%, rgba(168,85,247,0.05), transparent)' }}></div>
            </div>

            {/* Main Content Grid */}
            <div className="relative z-10 p-8 pt-10" style={{ display: 'grid', gridTemplateColumns: 'minmax(0, 7fr) 3fr', gap: '2rem', maxWidth: '1600px', margin: '0 auto' }}>

                {/* Left Column (Video & Notes) */}
                <div className="flex flex-col gap-6">

                    {/* Dynamic Title Block */}
                    <div className="mb-[-8px]">
                        <div className="text-cyan-500 dark:text-cyan-400 text-xs font-bold tracking-widest uppercase mb-2 ml-1">{displayChapterTitle}</div>
                        <h1 className="text-[32px] font-extrabold text-slate-900 dark:text-white tracking-tight leading-tight transition-colors duration-500">{displayTitle}</h1>
                        <p className="text-slate-500 dark:text-white/50 text-sm mt-3 flex items-center gap-3 ml-1 transition-colors duration-500">
                            <span className="px-2.5 py-1 rounded-md bg-white dark:bg-white/10 border border-gray-200 dark:border-white/5 text-xs font-mono text-slate-700 dark:text-white/80 shadow-sm dark:shadow-inner">{displayDuration}</span>
                            <span className="w-1 h-1 rounded-full bg-slate-300 dark:bg-white/30"></span>
                            <span className="font-medium tracking-wide">AI Generated Lecture</span>
                        </p>
                    </div>

                    <div className="bg-white dark:bg-white/5 backdrop-blur-md border border-gray-200 dark:border-white/10 rounded-2xl overflow-hidden shadow-sm dark:shadow-[0_0_40px_rgba(34,211,238,0.1)] flex flex-col transition-all duration-500">

                        {/* Video Area */}
                        <div className="aspect-video bg-black/50 relative flex items-center justify-center group">
                            {/* Glow accent */}
                            <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-cyan-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none"></div>

                            <Play size={64} className="text-white/80 hover:text-white hover:scale-110 transition-all cursor-pointer z-10 filter drop-shadow-[0_0_15px_rgba(34,211,238,0.5)]" onClick={togglePlay} />

                            {/* Custom Playback Controls Overlay */}
                            <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/90 via-black/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end">

                                {/* Progress Bar */}
                                <div className="w-full h-1.5 bg-white/20 rounded-full mb-3 cursor-pointer group/progress relative">
                                    <div className="absolute left-0 top-0 h-full w-[35%] bg-cyan-400 rounded-full shadow-[0_0_10px_rgba(34,211,238,0.8)]"></div>
                                    <div className="absolute left-[35%] top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-[0_0_5px_rgba(255,255,255,0.8)] opacity-0 group-hover/progress:opacity-100 transition-opacity transform -translate-x-1/2"></div>
                                </div>

                                {/* Controls Row */}
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-4">
                                        <button className="text-white hover:text-cyan-400 transition-colors" onClick={togglePlay}>
                                            {isPlaying ? <Pause size={20} /> : <Play size={20} />}
                                        </button>
                                        <button className="text-white hover:text-cyan-400 transition-colors"><Volume2 size={20} /></button>
                                        <div className="text-white/80 text-sm font-mono tracking-wider ml-2">02:15 / {displayDuration}</div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <button className="text-white/80 hover:text-white transition-colors"><Maximize size={20} /></button>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Action Bar */}
                        <div className="p-4 bg-gray-50 dark:bg-white/[0.02] border-t border-gray-200 dark:border-white/5 flex justify-between items-center transition-colors duration-500">

                            <button
                                onClick={() => navigate('/quiz')}
                                className="flex items-center gap-2 px-5 py-2.5 rounded-full border border-purple-500/50 text-purple-600 dark:text-purple-400 bg-purple-500/10 hover:bg-purple-500/20 hover:border-purple-500 dark:hover:border-purple-400 hover:text-purple-700 dark:hover:text-purple-300 transition-all shadow-[0_0_15px_rgba(168,85,247,0.15)] hover:shadow-[0_0_20px_rgba(168,85,247,0.3)] group"
                            >
                                <BrainCircuit size={18} className="group-hover:animate-pulse" />
                                <span className="text-sm font-semibold tracking-wide">Generate Quiz</span>
                            </button>

                            <div className="flex items-center gap-4">
                                {/* Language Toggle */}
                                <div className="flex items-center bg-white dark:bg-black/40 border border-gray-300 dark:border-white/10 rounded-full p-1 shadow-inner transition-colors duration-500">
                                    {['EN', 'HI', 'TE'].map(lang => (
                                        <button
                                            key={lang}
                                            onClick={() => setActiveLanguage(lang)}
                                            className={`px-3 py-1 rounded-full text-xs font-bold transition-all duration-300 ${activeLanguage === lang
                                                ? 'bg-slate-900 dark:bg-white/10 text-white dark:text-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.3)]'
                                                : 'text-slate-500 dark:text-white/40 hover:text-slate-800 dark:hover:text-white/70'
                                                }`}
                                        >
                                            {lang}
                                        </button>
                                    ))}
                                </div>

                                <div className="h-4 w-px bg-gray-300 dark:bg-white/10 transition-colors duration-500"></div>

                                <button className="flex items-center gap-2 px-4 py-2 rounded-lg text-slate-700 dark:text-white/70 bg-white dark:bg-white/5 hover:bg-gray-100 dark:hover:bg-white/10 hover:text-slate-900 dark:hover:text-white border border-gray-200 dark:border-white/5 hover:border-gray-300 dark:hover:border-white/10 transition-all text-sm font-medium">
                                    <Download size={16} /> Notes
                                </button>
                                <button className="flex items-center gap-2 px-4 py-2 rounded-lg text-slate-700 dark:text-white/70 bg-white dark:bg-white/5 hover:bg-gray-100 dark:hover:bg-white/10 hover:text-slate-900 dark:hover:text-white border border-gray-200 dark:border-white/5 hover:border-gray-300 dark:hover:border-white/10 transition-all text-sm font-medium">
                                    <Share2 size={16} /> Share
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="bg-white dark:bg-white/5 backdrop-blur-md border border-gray-200 dark:border-white/10 rounded-xl p-6 relative overflow-hidden group shadow-sm dark:shadow-none transition-colors duration-500">
                        {/* Shimmer effect */}
                        <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_2s_infinite] bg-gradient-to-r from-transparent via-black/[0.03] dark:via-white/[0.03] to-transparent pointer-events-none transition-colors duration-500"></div>

                        <div className="flex items-center gap-3 mb-5 border-b border-gray-200 dark:border-white/10 pb-4 transition-colors duration-500">
                            <div className="p-2 bg-cyan-500/10 rounded-lg border border-cyan-500/20 shadow-[0_0_10px_rgba(34,211,238,0.1)]">
                                <Sparkles size={20} className="text-cyan-600 dark:text-cyan-400 transition-colors duration-500" />
                            </div>
                            <div>
                                <h3 className="text-lg font-bold text-slate-900 dark:text-white tracking-wide flex items-center gap-2 transition-colors duration-500">
                                    Smart Notes <span className="px-2 py-0.5 rounded-full bg-slate-100 dark:bg-white/10 text-[10px] text-slate-500 dark:text-white/50 uppercase tracking-widest border border-gray-200 dark:border-white/5 transition-colors duration-500">Auto-Generated</span>
                                </h3>
                            </div>
                        </div>

                        <ul className="flex flex-col gap-4 pl-2">
                            {mockTakeaways[activeChapterId] ? mockTakeaways[activeChapterId].map((takeaway, idx) => (
                                <li key={idx} className="flex gap-4 items-start group/item">
                                    <div className="mt-1 flex items-center justify-center shrink-0">
                                        <Zap size={14} className="text-cyan-500/70 dark:text-cyan-400/70 group-hover/item:text-cyan-500 dark:group-hover/item:text-cyan-400 group-hover/item:filter group-hover/item:drop-shadow-[0_0_5px_rgba(34,211,238,0.8)] transition-all" />
                                    </div>
                                    <span className="text-slate-700 dark:text-gray-300 leading-relaxed text-[15px] transition-colors duration-500">{takeaway}</span>
                                </li>
                            )) : (
                                <li className="flex gap-4 items-start">
                                    <span className="text-slate-400 dark:text-white/40 italic transition-colors duration-500">Notes are being generated for this video...</span>
                                </li>
                            )}
                        </ul>
                    </div>

                </div>

                <div className="bg-white dark:bg-white/5 backdrop-blur-md border border-gray-200 dark:border-white/10 rounded-2xl flex flex-col h-[calc(100vh-10rem)] shadow-[0_4px_20px_rgba(0,0,0,0.05)] dark:shadow-xl hover:shadow-[0_8px_30px_rgba(0,0,0,0.08)] dark:hover:shadow-2xl overflow-hidden transition-all duration-500">

                    {/* Tab Header */}
                    <div className="flex border-b border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-black/20 transition-colors duration-500">
                        <button
                            className={`flex-[1] py-4 text-sm font-bold uppercase tracking-widest transition-all relative ${activeTab === 'curriculum' ? 'text-cyan-600 dark:text-cyan-400' : 'text-slate-500 dark:text-white/40 hover:text-slate-800 dark:hover:text-white/70'
                                }`}
                            onClick={() => setActiveTab('curriculum')}
                        >
                            Curriculum
                            {activeTab === 'curriculum' && (
                                <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-cyan-500 shadow-[0_0_10px_rgba(34,211,238,0.5)]"></div>
                            )}
                        </button>
                        <button
                            className={`flex-[1] py-4 text-sm font-bold uppercase tracking-widest transition-all relative flex items-center justify-center gap-2 ${activeTab === 'ask_ai' ? 'text-purple-600 dark:text-purple-400' : 'text-slate-500 dark:text-white/40 hover:text-slate-800 dark:hover:text-white/70'
                                }`}
                            onClick={() => setActiveTab('ask_ai')}
                        >
                            <BrainCircuit size={16} className={activeTab === 'ask_ai' ? 'animate-pulse' : ''} />
                            Ask AI
                            {activeTab === 'ask_ai' && (
                                <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.5)]"></div>
                            )}
                        </button>
                    </div>

                    {/* Tab Content Area */}
                    <div className="flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar">

                        {/* Curriculum Tab Content */}
                        {activeTab === 'curriculum' && (
                            <div className="flex flex-col">
                                <div className="p-5 border-b border-gray-200 dark:border-white/5 bg-gray-50 dark:bg-white/[0.02] transition-colors duration-500">
                                    <h4 className="text-slate-800 dark:text-white/80 font-semibold mb-1 transition-colors duration-500">Course Content</h4>
                                    <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-white/40 font-mono transition-colors duration-500">
                                        <span>{mockChapters.length} Chapters</span>
                                        <span>ΓÇó</span>
                                        <span>51 min total</span>
                                    </div>
                                </div>
                                <div className="flex flex-col">
                                    {displayChapters.map((chapter, idx) => {
                                        const isActive = activeVideoId === chapter.id;
                                        return (
                                            <div
                                                key={idx}
                                                onClick={() => setActiveVideoId(chapter.id)}
                                                className={`p-4 border-b border-gray-100 dark:border-white/5 cursor-pointer flex items-center justify-between transition-all group ${isActive
                                                    ? 'bg-cyan-50 dark:bg-cyan-500/10 border-l-[3px] border-l-cyan-500 dark:border-l-cyan-400 shadow-inner dark:shadow-[inset_0_0_20px_rgba(34,211,238,0.05)]'
                                                    : 'hover:bg-gray-50 dark:hover:bg-white/[0.03] border-l-[3px] border-l-transparent'
                                                    }`}
                                            >
                                                <div className="flex items-start gap-4 flex-1">
                                                    <div className={`mt-0.5 w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold border shrink-0 transition-colors duration-500 ${isActive ? 'border-cyan-300 dark:border-cyan-400/30 text-cyan-600 dark:text-cyan-400 bg-cyan-100 dark:bg-cyan-400/10 shadow-sm dark:shadow-[0_0_10px_rgba(34,211,238,0.2)]' : 'border-gray-200 dark:border-white/10 text-slate-400 dark:text-white/40 group-hover:border-gray-300 dark:group-hover:border-white/20'
                                                        }`}>
                                                        {idx + 1}
                                                    </div>
                                                    <div>
                                                        <div className={`text-sm mb-1 transition-colors duration-500 ${isActive ? 'text-cyan-700 dark:text-cyan-400 font-semibold' : 'text-slate-600 dark:text-gray-300 font-medium group-hover:text-slate-900 dark:group-hover:text-white/90'
                                                            }`}>
                                                            {chapter.title}
                                                        </div>
                                                        <div className="text-xs text-slate-400 dark:text-white/40 font-mono tracking-wide transition-colors duration-500">
                                                            {chapter.duration}
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="ml-4 shrink-0">
                                                    {isActive ? (
                                                        <div className="w-8 h-8 rounded-full bg-cyan-100 dark:bg-cyan-400/20 flex items-center justify-center shadow-sm dark:shadow-[0_0_15px_rgba(34,211,238,0.3)] transition-colors duration-500">
                                                            <div className="flex gap-1 items-end h-[14px]">
                                                                <div className="w-1 bg-cyan-500 dark:bg-cyan-400 animate-[bounce_1s_infinite_0ms] rounded-full"></div>
                                                                <div className="w-1 bg-cyan-500 dark:bg-cyan-400 animate-[bounce_1s_infinite_200ms] rounded-full"></div>
                                                                <div className="w-1 bg-cyan-500 dark:bg-cyan-400 animate-[bounce_1s_infinite_400ms] rounded-full"></div>
                                                            </div>
                                                        </div>
                                                    ) : (
                                                        <Play size={14} className="text-slate-300 dark:text-white/20 group-hover:text-slate-500 dark:group-hover:text-white/50 transition-colors ml-0.5" />
                                                    )}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {activeTab === 'ask_ai' && (
                            <div className="flex flex-col h-full bg-slate-50/50 dark:bg-black/10 transition-colors duration-500">
                                <div className="flex-1 p-5 overflow-y-auto flex flex-col gap-4">
                                    {chatMessages.map((msg, i) => (
                                        <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed transition-colors duration-500 ${msg.role === 'user'
                                                ? 'bg-white dark:bg-white/10 border border-gray-200 dark:border-white/20 text-slate-900 dark:text-white rounded-tr-sm shadow-sm'
                                                : 'bg-purple-50 dark:bg-purple-500/10 border border-purple-100 dark:border-purple-500/20 text-slate-800 dark:text-gray-200 rounded-tl-sm shadow-sm dark:shadow-[0_0_15px_rgba(168,85,247,0.05)]'
                                                }`}>
                                                {msg.role === 'ai' && (
                                                    <div className="flex items-center gap-2 mb-2 pb-2 border-b border-purple-200 dark:border-purple-500/20 transition-colors duration-500">
                                                        <BrainCircuit size={14} className="text-purple-600 dark:text-purple-400 transition-colors duration-500" />
                                                        <span className="text-[10px] uppercase tracking-widest text-purple-600/70 dark:text-purple-400/70 font-bold transition-colors duration-500">LecturAI Companion</span>
                                                    </div>
                                                )}
                                                <p>{msg.content}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>

                                <div className="p-4 border-t border-gray-200 dark:border-white/10 bg-white/95 dark:bg-black/40 backdrop-blur-md transition-colors duration-500">
                                    <form onSubmit={handleSendMessage} className="relative flex items-center">
                                        <input
                                            type="text"
                                            value={chatInput}
                                            onChange={(e) => setChatInput(e.target.value)}
                                            placeholder="Ask a doubt about this lecture..."
                                            className="w-full bg-white dark:bg-black/50 border border-gray-300 dark:border-white/20 rounded-full pl-5 pr-12 py-3 text-sm text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-white/40 shadow-sm focus:outline-none focus:border-purple-400 dark:focus:border-purple-500/50 focus:shadow-[0_0_15px_rgba(168,85,247,0.1)] dark:focus:shadow-[0_0_15px_rgba(168,85,247,0.2)] transition-all"
                                        />
                                        <button
                                            type="submit"
                                            disabled={!chatInput.trim()}
                                            className="absolute right-2 w-8 h-8 rounded-full bg-purple-100 dark:bg-purple-500/20 flex items-center justify-center border border-purple-200 dark:border-purple-500/40 text-purple-600 dark:text-purple-400 hover:bg-purple-200 dark:hover:bg-purple-500/40 hover:text-purple-800 dark:hover:text-purple-200 disabled:opacity-50 disabled:hover:bg-purple-100 dark:disabled:hover:bg-purple-500/20 disabled:hover:text-purple-600 dark:disabled:hover:text-purple-400 transition-all"
                                        >
                                            <Send size={14} className="ml-[-2px] mt-[1px]" />
                                        </button>
                                    </form>
                                    <div className="text-center mt-3">
                                        <p className="text-[10px] text-slate-400 dark:text-white/30 font-medium transition-colors duration-500">LecturAI can make mistakes. Consider verifying important information.</p>
                                    </div>
                                </div>
                            </div>
                        )}

                    </div>
                </div>

            </div>

            <style>{`
                @keyframes shimmer {
                    100% { transform: translateX(100%); }
                }
                .custom-scrollbar::-webkit-scrollbar {
                    width: 6px;
                }
                .custom-scrollbar::-webkit-scrollbar-track {
                    background: transparent;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb {
                    background-color: rgba(0,0,0,0.1);
                    border-radius: 20px;
                }
                .dark .custom-scrollbar::-webkit-scrollbar-thumb {
                    background-color: rgba(255,255,255,0.1);
                }
                .custom-scrollbar:hover::-webkit-scrollbar-thumb {
                    background-color: rgba(0,0,0,0.2);
                }
                .dark .custom-scrollbar:hover::-webkit-scrollbar-thumb {
                    background-color: rgba(255,255,255,0.2);
                }
            `}</style>
        </div>
    );
}

